mapper.select:
select id, appId, faitAmount, uAmount,account, proof, status, createTime, finishTime, rate
from settlementlog
where 1=1

    and
    appId = #{appId}


    and
    status = #{status}


    and
    createTime >= #{startCreateTime}


    and
    createTime <= #{endCreateTime}


    and
    finishTime >= #{startFinishTime}


    and
    finishTime <= #{endFinishTime}

order by CreateTime desc

    limit ${rowIndex},${limit}

select count(if(status = 0,id,null)) as processedNum,
sum(if(status = 0,faitAmount,0)) as processedFiatAmount,
count(id) as totalAllNum,
sum(faitAmount) as totalFailAmount,
sum(uAmount) as totalUAmount
from settlementlog
where 1=1

    and
    appId = #{appId}


    and
    status = #{status}


    and
    createTime >= #{startCreateTime}


    and
    createTime <= #{endCreateTime}


    and
    finishTime >= #{startFinishTime}


    and
    finishTime <= #{endFinishTime}
